import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";

function ViewAnswers() {
  const { id } = useParams();
  const [question, setQuestion] = useState(null);

  const user = JSON.parse(localStorage.getItem("user") || "null");

  // FETCH QUESTION
  useEffect(() => {
    fetch(`http://localhost:5000/api/questions`)
      .then((res) => res.json())
      .then((data) => {
        const q = data.find((item) => item._id === id);
        setQuestion(q);
      });
  }, [id]);

  // LIKE FUNCTION
  const handleLike = async () => {
    const res = await fetch(
      `http://localhost:5000/api/questions/like/${id}`,
      {
        method: "PUT",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ userEmail: user.email }),
      }
    );

    const data = await res.json();

    // update UI
    setQuestion((prev) => ({
      ...prev,
      likes: Array(data.likes).fill("x"),
    }));
  };

  if (!question) return <p>Loading...</p>;

  return (
    <div className="page-center">
      <div className="card">

        <h3>{question.title}</h3>

        <p><b>Description:</b> {question.description}</p>

        {question.file && (
          <a
            href={`http://localhost:5000/uploads/${question.file}`}
            target="_blank"
            rel="noreferrer"
          >
            📎 View File
          </a>
        )}

        {/* ❤️ LIKE BUTTON */}
        <button onClick={handleLike} className="btn">
          ❤️ Like ({question.likes?.length || 0})
        </button>

      </div>
    </div>
  );
}

export default ViewAnswers;
